#include <bits/stdc++.h>
#define int long long
using namespace std;
int n, m;
int k;
int a[1000005];
int nxt[1000005];
int tmp[1000005];
int ans[1000005];
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n >> k >> m;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	nxt[1] = k + 1; 
	int head = 1, tail = k + 1;
	for (int i = 2; i <= n; i++)  {
		while (tail + 1 <= n && a[i] - a[head] > a[tail + 1] - a[i]) {
			head++;
			tail++;
		}
		if (a[i] - a[head] >= a[tail] - a[i]) {
			nxt[i] = head;
		} else {
			nxt[i] = tail;
		}
	}
	for (int i = 1; i <= n; i++) {
		ans[i] = i;
	}
	while (m) {
		if (m & 1) {
			for (int i = 1; i <= n; i++) {
				ans[i] = nxt[ans[i]];
			}
		}
		memcpy (tmp, nxt, sizeof (tmp));
		for (int i = 1; i <= n; i++) {
			nxt[i] = tmp[tmp[i]];
		}
		m >>= 1;
	}
	for (int i = 1; i <= n; i++) {
		cout << ans[i] << ' ';
	}
	return 0;
}
